with open('data/text_he.js', 'r', encoding='utf-8') as f:
    content = f.read()
idx = content.index('=')
content_clean = content[idx+1:].strip().rstrip(';')
data = json.loads(content_clean)
book2 = data[1]
by_num = {c['number']: i for i, c in enumerate(book2['cantos'])}
for num, title, paras in HE:
    entry = {'number': num, 'title': title, 'paragraphs': paras}
    if num in by_num:
        book2['cantos'][by_num[num]] = entry
    else:
        print(f"WARNING: canto {num} not found in book2")

with open('data/text_he.js', 'w', encoding='utf-8') as f:
    f.write('var RAMAYANA_TEXT_HE = ' + json.dumps(data, ensure_ascii=False, indent=2) + ';')

print("Done. Verifying Hebrew content...")
for num, title, paras in HE:
    he_count = sum(sum(1 for ch in p if 'א' <= ch <= 'ת') for p in paras)
    print(f"  Canto {num}: {he_count} Hebrew chars — {'OK' if he_count > 30 else 'FAIL'}")
